import numpy as np
from sklearn.preprocessing import StandardScaler


class Pipeline:
    def __init__(self):
        self.scaler = StandardScaler()

    def fit_and_transform(self, X):
        # BUG: X is 1D array, scaler requires 2D
        return self.scaler.fit_transform(X)


def fit_and_transform(X):
    p = Pipeline()
    return p.fit_and_transform(X)


def main():
    np.random.seed(0)
    data = np.random.rand(100) * 10  # 1D!
    result = fit_and_transform(data)
    print(result.shape)


if __name__ == '__main__':
    main()
